# Authentication Interceptor
class AuthInterceptor(grpc.ServerInterceptor):
    def __init__(self, exempt_methods=None):
        self.exempt_methods = exempt_methods or []
    
    def _is_exempt(self, method_name):
        for exempt in self.exempt_methods:
            if exempt.endswith('*'):
                if method_name.startswith(exempt[:-1]):
                    return True
            elif method_name == exempt:
                return True
        return False
    
    def _verify_token(self, metadata):
        metadata_dict = dict(metadata)
        auth_header = metadata_dict.get('authorization', '')
        
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            # Simple token validation
            if token and len(token) > 10:
                return True
        return False
    
    def intercept_service(self, continuation, handler_call_details):
        method_name = handler_call_details.method
        
        if self._is_exempt(method_name):
            return continuation(handler_call_details)
        
        metadata = handler_call_details.invocation_metadata
        
        if not self._verify_token(metadata):
            def abort(ignored_request, context):
                context.abort(StatusCode.UNAUTHENTICATED, 'Invalid or missing authentication token')
            
            return grpc.unary_unary_rpc_method_handler(abort)
        
        return continuation(handler_call_details)

